    11→ */
    12→
    13→export interface ValidationResult {
    14→  isValid: boolean;
    15→  errors: ValidationError[];
    16→  warnings: ValidationWarning[];
    17→  performance: ValidationPerformance;
    18→  summary: ValidationSummary;
    19→}
