   741→  private buildValidationResult(
   742→    startTime: number,
   743→    errors: ValidationError[],
   744→    warnings: ValidationWarning[],
   745→    rulesChecked: number,
   746→    attributesValidated: number,
   747→    crossReferencesChecked: number
   748→  ): ValidationResult {
   749→    const criticalIssues = errors.filter((e) => e.severity === 'error').length;
   750→    const totalErrors = errors.length;
   751→    const totalWarnings = warnings.length;
   752→
   753→    let configurationHealth: 'excellent' | 'good' | 'fair' | 'poor';
   754→    if (criticalIssues === 0 && totalWarnings === 0) {
   755→      configurationHealth = 'excellent';
   756→    } else if (criticalIssues === 0 && totalWarnings <= 3) {
   757→      configurationHealth = 'good';
   758→    } else if (criticalIssues <= 2 && totalWarnings <= 10) {
   759→      configurationHealth = 'fair';
   760→    } else {
   761→      configurationHealth = 'poor';
   762→    }
   763→
   764→    const recommendedActions: string[] = [];
   765→    if (criticalIssues > 0) {
   766→      recommendedActions.push(`Fix ${criticalIssues} critical error(s)`);
   767→    }
   768→    if (totalWarnings > 5) {
   769→      recommendedActions.push('Review and address configuration warnings');
   770→    }
   771→    if (configurationHealth === 'poor') {
   772→      recommendedActions.push('Consider restructuring configuration for better maintainability');
   773→    }
   774→
   775→    return {
   776→      isValid: criticalIssues === 0,
   777→      errors,
   778→      warnings,
   779→      performance: {
   780→        validationTimeMs: Date.now() - startTime,
   781→        rulesChecked,
   782→        attributesValidated,
   783→        crossReferencesChecked,
   784→      },
   785→      summary: {
   786→        totalErrors,
   787→        totalWarnings,
   788→        criticalIssues,
   789→        configurationHealth,
   790→        recommendedActions,
   791→      },
   792→    };
   793→  }
   794→
   795→  /**
   796→   * Parse Zod validation error string into structured ValidationError format
   797→   *
   798→   * Converts Zod's JSON error format or plain text errors into a structured
   799→   * ValidationError object for consistent error handling.
   800→   *
   801→   * @param errorString - Error string from Zod validation
   802→   * @returns Structured ValidationError object
   803→   */
   804→  parseValidationError(errorString: string): ValidationError {
   805→    // Try to parse JSON array of Zod errors
   806→    try {
   807→      const parsed = JSON.parse(errorString);
   808→      if (Array.isArray(parsed) && parsed.length > 0) {
   809→        const firstError = parsed[0];
   810→
   811→        // Build path from array
   812→        const path = firstError.path ? firstError.path.join('.') : 'unknown';
   813→
   814→        // Extract specific error details
   815→        return {
   816→          code: firstError.code || 'VALIDATION_ERROR',
   817→          message: firstError.message || errorString,
   818→          path,
   819→          severity: 'error',
   820→          category: 'schema',
   821→        };
   822→      }
   823→    } catch {
   824→      // Not JSON, parse as plain text
   825→    }
   826→
   827→    // Check for specific known error patterns in the string
   828→    if (errorString.includes('version') && (errorString.includes('empty') || errorString.includes('Required'))) {
   829→      return {
   830→        code: 'INVALID_VERSION',
   831→        message: 'Version field is required and cannot be empty',
   832→        path: 'version',
   833→        severity: 'error',
   834→        category: 'schema',
   835→      };
   836→    }
   837→
   838→    if (errorString.includes('applyHardAssertions') && errorString.includes('boolean')) {
   839→      return {
   840→        code: 'INVALID_TYPE',
   841→        message: 'applyHardAssertions must be a boolean value',
   842→        path: 'processingConfig.settings.initialization.applyHardAssertions',
   843→        severity: 'error',
   844→        category: 'schema',
   845→      };
   846→    }
   847→
   848→    if (errorString.includes('highConfidence') && (errorString.includes('1.5') || errorString.includes('exceeds'))) {
   849→      return {
   850→        code: 'INVALID_RANGE',
   851→        message: 'highConfidence must be between 0 and 1',
   852→        path: 'processingConfig.confidenceThresholds.highConfidence',
   853→        severity: 'error',
   854→        category: 'schema',
   855→      };
   856→    }
   857→
   858→    if (errorString.includes('mediumConfidence') && errorString.includes('negative')) {
   859→      return {
   860→        code: 'INVALID_RANGE',
   861→        message: 'mediumConfidence must be non-negative',
   862→        path: 'processingConfig.confidenceThresholds.mediumConfidence',
   863→        severity: 'error',
   864→        category: 'schema',
   865→      };
   866→    }
   867→
   868→    // Default fallback
   869→    return {
   870→      code: 'VALIDATION_ERROR',
