import { CategoryConfiguration, validateCategoryConfiguration, getValidationErrors } from './category-config-schema';
import {
  ProcessingConfigTuning,
  validateProcessingConfigTuning,
  getProcessingConfigErrors,
} from './processing-config-schema';

/**
 * Configuration validation service
 * Provides comprehensive validation for all configuration types
 */

export interface ValidationResult {
  isValid: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
  performance: ValidationPerformance;
  summary: ValidationSummary;
}

export interface ValidationError {
  code: string;
  message: string;
  path: string;
  severity: 'error' | 'warning';
  category: 'schema' | 'logic' | 'reference' | 'performance' | 'security';
  suggestion?: string;
}

export interface ValidationWarning {
  code: string;
  message: string;
  path: string;
  impact: 'low' | 'medium' | 'high';
  recommendation: string;
}

export interface ValidationPerformance {
  validationTimeMs: number;
  rulesChecked: number;
  attributesValidated: number;
  crossReferencesChecked: number;
}

export interface ValidationSummary {
  totalErrors: number;
  totalWarnings: number;
  criticalIssues: number;
  configurationHealth: 'excellent' | 'good' | 'fair' | 'poor';
  recommendedActions: string[];
}

export interface CrossReferenceCheck {
  attributeReferences: string[];
  domainReferences: string[];
  categoryReferences: string[];
  orphanedReferences: string[];
}

export interface ValidationOptions {
  skipCrossReferences?: boolean;
  skipPerformanceChecks?: boolean;
  skipSecurityChecks?: boolean;
  skipQualityChecks?: boolean;
  strictMode?: boolean;
}

export class ConfigurationValidator {
  constructor() {
    // No initialization needed
  }

  /**
   * Validate category configuration with comprehensive checks
   */
  async validateCategoryConfiguration(
    config: CategoryConfiguration | unknown,
    _options: ValidationOptions = {}
  ): Promise<ValidationResult> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    let validatedConfig: CategoryConfiguration | undefined;

    // Schema validation
    try {
      if (typeof config === 'object' && config !== null && 'processingConfig' in config) {
        validatedConfig = config as CategoryConfiguration;
        validateCategoryConfiguration(config);
      } else {
        validatedConfig = validateCategoryConfiguration(config);
      }
    } catch {
      // Schema validation failed, but continue with logic checks for comprehensive error reporting
      const schemaErrors = getValidationErrors(config);
      errors.push(...schemaErrors.map((err) => this.parseValidationError(err)));

      // Try to use the config as-is for additional validation checks
      if (typeof config === 'object' && config !== null && 'processingConfig' in config) {
        validatedConfig = config as CategoryConfiguration;
      }
    }

    // Initialize cross-reference result
    let crossRefResult: { errors: ValidationError[]; warnings: ValidationWarning[]; totalChecks: number } = {
      errors: [],
      warnings: [],
      totalChecks: 0,
    };

    // Only run additional checks if we have a minimally valid config structure
    if (validatedConfig && validatedConfig.processingConfig) {
      // Logic validation
      const logicErrors = await this.validateConfigurationLogic(validatedConfig);
      errors.push(...logicErrors);

      // Rule conflict detection
      const ruleConflictErrors = this.detectRuleConflicts(validatedConfig);
      errors.push(...ruleConflictErrors);

      // Attribute matrix validation
      const attributeMatrixErrors = this.validateAttributeMatrix(validatedConfig);
      errors.push(...attributeMatrixErrors);

      // Cross-reference validation
      crossRefResult = await this.validateCrossReferences(validatedConfig);
      errors.push(...crossRefResult.errors);
      warnings.push(...crossRefResult.warnings);

      // Performance validation
      const perfResult = await this.validatePerformanceSettings(validatedConfig);
      warnings.push(...perfResult.warnings);

      // Security validation
      const securityResult = await this.validateSecuritySettings(validatedConfig);
      errors.push(...securityResult.errors);
      warnings.push(...securityResult.warnings);

      // Configuration quality checks
      const qualityWarnings = await this.validateConfigurationQuality(validatedConfig);
      warnings.push(...qualityWarnings);
    }

    const performance = {
      validationTimeMs: Date.now() - startTime,
      rulesChecked: validatedConfig ? this.countRules(validatedConfig) : 0,
      attributesValidated: validatedConfig?.processingConfig?.attributes?.schema
        ? Object.keys(validatedConfig.processingConfig.attributes.schema).length
        : 0,
      crossReferencesChecked: validatedConfig ? crossRefResult.totalChecks : 0,
    };

    return this.buildValidationResult(
      startTime,
      errors,
      warnings,
      performance.rulesChecked,
      performance.attributesValidated,
      performance.crossReferencesChecked
    );
  }

  /**
   * Validate processing configuration tuning parameters
   */
  async validateProcessingConfigurationTuning(
    config: ProcessingConfigTuning | unknown,
    _options: ValidationOptions = {}
  ): Promise<ValidationResult> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    let validatedConfig: ProcessingConfigTuning;

    // Schema validation
    try {
      validatedConfig = validateProcessingConfigTuning(config);
    } catch (error) {
      console.error('Processing configuration schema validation failed:', error);
      const schemaErrors = getProcessingConfigErrors(config);
      errors.push(
        ...schemaErrors.map((err) => ({
          code: 'PROCESSING_SCHEMA_VALIDATION_FAILED',
          message: err,
          path: 'root',
          severity: 'error' as const,
          category: 'schema' as const,
          suggestion: 'Check the processing configuration structure against the schema',
        }))
      );

      return this.buildValidationResult(startTime, errors, warnings, 0, 0, 0);
    }

    // Tuning parameter validation
    const tuningErrors = await this.validateTuningParameters(validatedConfig);
    errors.push(...tuningErrors.errors);
    warnings.push(...tuningErrors.warnings);

    // Performance consistency validation
    const consistencyWarnings = await this.validatePerformanceConsistency(validatedConfig);
    warnings.push(...consistencyWarnings);

    const performance = {
      validationTimeMs: Date.now() - startTime,
      rulesChecked: 0,
      attributesValidated: 0,
      crossReferencesChecked: 0,
    };

    return this.buildValidationResult(
      startTime,
      errors,
      warnings,
      performance.rulesChecked,
      performance.attributesValidated,
      performance.crossReferencesChecked
    );
  }

  /**
   * Validate domain sources configuration
   */
  async validateDomainSources(
    config: Record<string, string[]> | unknown,
    _options: ValidationOptions = {}
  ): Promise<ValidationResult> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    if (!config || typeof config !== 'object') {
      errors.push({
        code: 'INVALID_DOMAIN_SOURCES_TYPE',
        message: 'Domain sources must be an object',
        path: 'root',
        severity: 'error',
        category: 'schema',
      });
      return this.buildValidationResult(startTime, errors, warnings, 0, 0, 0);
    }

    const domainSources = config as Record<string, string[]>;

    // Validate domain groups
    for (const [groupName, domains] of Object.entries(domainSources)) {
      if (!Array.isArray(domains)) {
        errors.push({
          code: 'INVALID_DOMAIN_GROUP_TYPE',
          message: `Domain group "${groupName}" must be an array`,
          path: groupName,
          severity: 'error',
          category: 'schema',
        });
        continue;
      }

      // Validate individual domains
      for (let i = 0; i < domains.length; i++) {
        const domain = domains[i];
        if (typeof domain !== 'string') {
          errors.push({
            code: 'INVALID_DOMAIN_TYPE',
            message: `Domain at index ${i} in group "${groupName}" must be a string`,
            path: `${groupName}[${i}]`,
            severity: 'error',
            category: 'schema',
          });
          continue;
        }

        // Validate domain format
        if (!/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/.test(domain)) {
          errors.push({
            code: 'INVALID_DOMAIN_FORMAT',
            message: `Invalid domain format: "${domain}" in group "${groupName}"`,
            path: `${groupName}[${i}]`,
            severity: 'error',
            category: 'logic',
            suggestion: 'Use valid domain format like "example.com"',
          });
        }
      }

      // Check for duplicate domains within group
      const uniqueDomains = new Set(domains);
      if (uniqueDomains.size !== domains.length) {
        warnings.push({
          code: 'DUPLICATE_DOMAINS_IN_GROUP',
          message: `Group "${groupName}" contains duplicate domains`,
          path: groupName,
          impact: 'low',
          recommendation: 'Remove duplicate domains to improve configuration clarity',
        });
      }
    }

    // Check for domains appearing in multiple groups
    const allDomains = new Map<string, string[]>();
    for (const [groupName, domains] of Object.entries(domainSources)) {
      for (const domain of domains) {
        if (!allDomains.has(domain)) {
          allDomains.set(domain, []);
        }
        allDomains.get(domain)!.push(groupName);
      }
    }

    for (const [domain, groups] of Array.from(allDomains.entries())) {
      if (groups.length > 1) {
        warnings.push({
          code: 'DOMAIN_IN_MULTIPLE_GROUPS',
          message: `Domain "${domain}" appears in multiple groups: ${groups.join(', ')}`,
          path: 'cross-reference',
          impact: 'medium',
          recommendation: 'Consider if this domain should only be in one group for clarity',
        });
      }
    }

    return this.buildValidationResult(startTime, errors, warnings, 0, 0, allDomains.size);
  }

  /**
   * Validate complete configuration suite (category + processing + domains)
   */
  async validateCompleteConfiguration(
    categoryConfig: CategoryConfiguration,
    processingConfig: ProcessingConfigTuning,
    domainSources: Record<string, string[]>,
    options: ValidationOptions = {}
  ): Promise<ValidationResult> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    // Validate individual configurations
    const categoryResult = await this.validateCategoryConfiguration(categoryConfig, options);
    const processingResult = await this.validateProcessingConfigurationTuning(processingConfig, options);
    const domainResult = await this.validateDomainSources(domainSources, options);

    errors.push(...categoryResult.errors, ...processingResult.errors, ...domainResult.errors);
    warnings.push(...categoryResult.warnings, ...processingResult.warnings, ...domainResult.warnings);

    // Cross-configuration validation
    const crossConfigErrors = await this.validateCrossConfigurationReferences(categoryConfig, domainSources);
    errors.push(...crossConfigErrors);

    const totalChecks =
      categoryResult.performance.crossReferencesChecked +
      processingResult.performance.crossReferencesChecked +
      domainResult.performance.crossReferencesChecked;

    return this.buildValidationResult(
      startTime,
      errors,
      warnings,
      categoryResult.performance.rulesChecked,
      categoryResult.performance.attributesValidated,
      totalChecks
    );
  }

  // Private validation methods

  private async validateConfigurationLogic(config: CategoryConfiguration): Promise<ValidationError[]> {
    const errors: ValidationError[] = [];

    // Skip if topLevelCategories is not defined
    if (!config.processingConfig?.topLevelCategories) {
      return errors;
    }

    // Validate category consistency
    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
      // Validate subtypes
      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
        if (subtype.derived && !subtype.derivationLogic) {
          errors.push({
            code: 'MISSING_DERIVATION_LOGIC',
            message: `Derived subtype "${categoryName}.${subtypeName}" has no derivation logic`,
            path: `topLevelCategories.${categoryName}.subtypes.${subtypeName}`,
            severity: 'error',
            category: 'logic',
            suggestion: 'Add derivationLogic or set derived to false',
          });
        }
      }
    }

    return errors;
  }

  private async validateCrossReferences(config: CategoryConfiguration): Promise<{
    errors: ValidationError[];
    warnings: ValidationWarning[];
    totalChecks: number;
  }> {
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];
    let totalChecks = 0;

    // Skip if attributes or relevance matrix is not defined
    if (!config.processingConfig?.attributes?.schema || !config.processingConfig?.attributeRelevance) {
      return { errors, warnings, totalChecks };
    }

    // Get defined attributes
    const definedAttributes = new Set(Object.keys(config.processingConfig.attributes.schema));

    // Check attribute references in relevance matrix
    for (const [categoryName, categoryConfig] of Object.entries(config.processingConfig.attributeRelevance)) {
      if (categoryName === '_roles_legend') continue;

      totalChecks++;

      // Type guard to ensure we have the correct structure
      if (
        typeof categoryConfig === 'object' &&
        categoryConfig !== null &&
        'categoryRoles' in categoryConfig &&
        categoryConfig.categoryRoles
      ) {
        for (const attributeName of Object.keys(categoryConfig.categoryRoles)) {
          totalChecks++;
          if (!definedAttributes.has(attributeName)) {
            errors.push({
              code: 'UNDEFINED_ATTRIBUTE_REFERENCE',
              message: `Category "${categoryName}" references undefined attribute: "${attributeName}"`,
              path: `attributeRelevance.${categoryName}.categoryRoles.${attributeName}`,
              severity: 'error',
              category: 'reference',
              suggestion: `Define attribute "${attributeName}" in attributes.schema or remove the reference`,
            });
          }
        }
      }
    }

    // Check for orphaned attributes (defined but not used in any category)
    const usedAttributes = new Set<string>();
    for (const [categoryName, categoryConfig] of Object.entries(config.processingConfig.attributeRelevance)) {
      if (categoryName === '_roles_legend' || categoryName === 'RolesLegend') continue;
      // Type guard to ensure we have the correct structure
      if (typeof categoryConfig === 'object' && categoryConfig !== null && 'categoryRoles' in categoryConfig) {
        if (categoryConfig.categoryRoles) {
          Object.keys(categoryConfig.categoryRoles).forEach((attr) => usedAttributes.add(attr));
        }
      }
    }

    // Determine if this is a minimal/incomplete config
    // A config is minimal if it's missing either top-level categories OR category signals
    // UNLESS it has rule-based classification defined in subtypes
    const hasTopLevelCategories =
      config.processingConfig.topLevelCategories && Object.keys(config.processingConfig.topLevelCategories).length > 0;
    const hasCategorySignals =
      config.processingConfig.categorySignals && Object.keys(config.processingConfig.categorySignals).length > 0;

    // Check if config has rule-based classification (makes it non-minimal even without signals)
    let hasRuleBasedClassification = false;
    if (hasTopLevelCategories) {
      for (const category of Object.values(config.processingConfig.topLevelCategories)) {
        for (const subtype of Object.values(category.subtypes)) {
          if (subtype.ruleBasedClassification) {
            hasRuleBasedClassification = true;
            break;
          }
        }
        if (hasRuleBasedClassification) break;
      }
    }

    const isMinimalConfig = (!hasTopLevelCategories || !hasCategorySignals) && !hasRuleBasedClassification;

    for (const attributeName of Array.from(definedAttributes)) {
      totalChecks++;
      if (!usedAttributes.has(attributeName)) {
        // For minimal configs, orphaned attributes are errors (incomplete matrix)
        // For complete configs, orphaned attributes are warnings (quality issue)
        if (isMinimalConfig) {
          errors.push({
            code: 'INCOMPLETE_ATTRIBUTE_MATRIX',
            message: `Attribute "${attributeName}" is defined but not used in any category`,
            path: `attributes.schema.${attributeName}`,
            severity: 'error',
            category: 'reference',
            suggestion: 'Remove unused attribute from schema or add to category relevance matrix',
          });
        } else {
          warnings.push({
            code: 'ORPHANED_ATTRIBUTE',
            message: `Attribute "${attributeName}" is defined but not used in any category`,
            path: `attributes.schema.${attributeName}`,
            impact: 'low',
            recommendation: 'Consider removing unused attributes or adding them to relevance matrix',
          });
        }
      }
    }

    return { errors, warnings, totalChecks };
  }

  private async validatePerformanceSettings(config: CategoryConfiguration): Promise<{
    warnings: ValidationWarning[];
  }> {
    const warnings: ValidationWarning[] = [];

    // Skip if topLevelCategories is not defined
    if (!config.processingConfig?.topLevelCategories) {
      return { warnings };
    }

    // Check for performance optimization opportunities
    const totalRules = this.countRules(config);
    if (totalRules > 1000) {
      warnings.push({
        code: 'HIGH_RULE_COUNT',
        message: `Configuration has ${totalRules} rules, which may impact performance`,
        path: 'topLevelCategories',
        impact: 'medium',
        recommendation: 'Consider optimizing rules or enabling rule compilation',
      });
    }

    const totalCategories = Object.keys(config.processingConfig.topLevelCategories).length;
    if (totalCategories > 20) {
      warnings.push({
        code: 'HIGH_CATEGORY_COUNT',
        message: `Configuration has ${totalCategories} categories, which may impact classification performance`,
        path: 'topLevelCategories',
        impact: 'medium',
        recommendation: 'Consider consolidating related categories',
      });
    }

    return { warnings };
  }

  private async validateSecuritySettings(config: CategoryConfiguration): Promise<{
    errors: ValidationError[];
    warnings: ValidationWarning[];
  }> {
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    // Skip if topLevelCategories is not defined
    if (!config.processingConfig?.topLevelCategories) {
      return { errors, warnings };
    }

    // Check for potentially dangerous regex patterns
    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
        if (subtype.ruleBasedClassification) {
          for (const [tier, rules] of Object.entries(subtype.ruleBasedClassification)) {
            if (rules) {
              for (const rule of rules) {
                if (rule.operation === 'regexAny' && rule.values) {
                  for (const pattern of rule.values) {
                    if (this.isDangerousRegex(pattern)) {
                      warnings.push({
                        code: 'DANGEROUS_REGEX_PATTERN',
                        message: `Potentially dangerous regex pattern in ${categoryName}.${subtypeName}.${tier}: "${pattern}"`,
                        path: `topLevelCategories.${categoryName}.subtypes.${subtypeName}.ruleBasedClassification.${tier}`,
                        impact: 'high',
                        recommendation: 'Review regex pattern for potential ReDoS vulnerability',
                      });
                    }
                  }
                }
              }
            }
          }
        }
      }
    }

    return { errors, warnings };
  }

  private async validateConfigurationQuality(config: CategoryConfiguration): Promise<ValidationWarning[]> {
    const warnings: ValidationWarning[] = [];

    // Skip if topLevelCategories is not defined
    if (!config.processingConfig?.topLevelCategories) {
      return warnings;
    }

    // Check for empty categories
    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
      if (Object.keys(category.subtypes).length === 0) {
        warnings.push({
          code: 'EMPTY_CATEGORY',
          message: `Category "${categoryName}" has no subtypes defined`,
          path: `topLevelCategories.${categoryName}`,
          impact: 'medium',
          recommendation: 'Add subtypes or remove the empty category',
        });
      }
    }

    // Check for categories without AI classification
    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
      if (category.aiFinalClassification && !category.aiFinalClassification.decisionCriteria?.length) {
        warnings.push({
          code: 'MISSING_AI_CRITERIA',
          message: `Category "${categoryName}" has no AI decision criteria`,
          path: `topLevelCategories.${categoryName}.aiFinalClassification`,
          impact: 'medium',
          recommendation: 'Add decision criteria for AI classification fallback',
        });
      }
    }

    return warnings;
  }

  private async validateTuningParameters(config: ProcessingConfigTuning): Promise<{
    errors: ValidationError[];
    warnings: ValidationWarning[];
  }> {
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    // Validate threshold relationships
    if (config.aiRoutingTuning) {
      const ai = config.aiRoutingTuning;
      if (ai.highConfidenceThreshold <= ai.aiRequiredThreshold) {
        errors.push({
          code: 'INVALID_THRESHOLD_RELATIONSHIP',
          message: 'highConfidenceThreshold must be greater than aiRequiredThreshold',
          path: 'aiRoutingTuning',
          severity: 'error',
          category: 'logic',
          suggestion: 'Adjust thresholds so highConfidenceThreshold > aiRequiredThreshold',
        });
      }
    }

    // Validate performance settings
    if (config.performanceTuning) {
      const perf = config.performanceTuning;
      if (perf.maxParallelEmails && perf.emailBatchSize) {
        if (perf.maxParallelEmails > perf.emailBatchSize) {
          warnings.push({
            code: 'INEFFICIENT_PARALLEL_SETTINGS',
            message: 'maxParallelEmails exceeds emailBatchSize',
            path: 'performanceTuning',
            impact: 'medium',
            recommendation: 'Set maxParallelEmails <= emailBatchSize for optimal batching',
          });
        }
      }
    }

    return { errors, warnings };
  }

  private async validatePerformanceConsistency(config: ProcessingConfigTuning): Promise<ValidationWarning[]> {
    const warnings: ValidationWarning[] = [];

    // Check for conflicting performance settings
    if (config.performanceTuning?.parallelProcessingEnabled === false) {
      if (config.attributeDetectionTuning?.parallelDetectionEnabled === true) {
        warnings.push({
          code: 'CONFLICTING_PARALLEL_SETTINGS',
          message: 'Global parallel processing is disabled but attribute detection parallelism is enabled',
          path: 'performanceTuning.parallelProcessingEnabled',
          impact: 'medium',
          recommendation: 'Align parallel processing settings for consistency',
        });
      }
    }

    return warnings;
  }

  private async validateCrossConfigurationReferences(
    categoryConfig: CategoryConfiguration,
    domainSources: Record<string, string[]>
  ): Promise<ValidationError[]> {
    const errors: ValidationError[] = [];

    // Validate domain references
    const availableDomainGroups = new Set(Object.keys(domainSources));

    for (const [categoryName, signals] of Object.entries(categoryConfig.processingConfig.categorySignals)) {
      if (signals.hardAssertions?.fromDomainsRef) {
        const groupName = signals.hardAssertions.fromDomainsRef.sourceGroup;
        if (!availableDomainGroups.has(groupName)) {
          errors.push({
            code: 'INVALID_DOMAIN_GROUP_REFERENCE',
            message: `Category "${categoryName}" references undefined domain group: "${groupName}"`,
            path: `categorySignals.${categoryName}.hardAssertions.fromDomainsRef.sourceGroup`,
            severity: 'error',
            category: 'reference',
            suggestion: `Define domain group "${groupName}" in domain sources or update the reference`,
          });
        }
      }
    }

    return errors;
  }

  private countRules(config: CategoryConfiguration): number {
    let count = 0;
    if (!config.processingConfig?.topLevelCategories) {
      return count;
    }
    for (const category of Object.values(config.processingConfig.topLevelCategories)) {
      for (const subtype of Object.values(category.subtypes)) {
        if (subtype.ruleBasedClassification) {
          for (const rules of Object.values(subtype.ruleBasedClassification)) {
            if (rules) {
              count += rules.length;
            }
          }
        }
      }
    }
    return count;
  }

  private isDangerousRegex(pattern: string): boolean {
    // Basic check for potentially dangerous regex patterns
    const dangerousPatterns = [
      /\(.*\+.*\).*\+/, // Nested quantifiers
      /\(.*\*.*\).*\*/, // Nested quantifiers
      /\([^)]*\+[^)]*\)\+/, // Nested quantifiers
      /\([^)]*\*[^)]*\)\*/, // Nested quantifiers
    ];

    return dangerousPatterns.some((dangerous) => dangerous.test(pattern));
  }

  private buildValidationResult(
    startTime: number,
    errors: ValidationError[],
    warnings: ValidationWarning[],
    rulesChecked: number,
    attributesValidated: number,
    crossReferencesChecked: number
  ): ValidationResult {
    const criticalIssues = errors.filter((e) => e.severity === 'error').length;
    const totalErrors = errors.length;
    const totalWarnings = warnings.length;

    let configurationHealth: 'excellent' | 'good' | 'fair' | 'poor';
    if (criticalIssues === 0 && totalWarnings === 0) {
      configurationHealth = 'excellent';
    } else if (criticalIssues === 0 && totalWarnings <= 3) {
      configurationHealth = 'good';
    } else if (criticalIssues <= 2 && totalWarnings <= 10) {
      configurationHealth = 'fair';
    } else {
      configurationHealth = 'poor';
    }

    const recommendedActions: string[] = [];
    if (criticalIssues > 0) {
      recommendedActions.push(`Fix ${criticalIssues} critical error(s)`);
    }
    if (totalWarnings > 5) {
      recommendedActions.push('Review and address configuration warnings');
    }
    if (configurationHealth === 'poor') {
      recommendedActions.push('Consider restructuring configuration for better maintainability');
    }

    return {
      isValid: criticalIssues === 0,
      errors,
      warnings,
      performance: {
        validationTimeMs: Date.now() - startTime,
        rulesChecked,
        attributesValidated,
        crossReferencesChecked,
      },
      summary: {
        totalErrors,
        totalWarnings,
        criticalIssues,
        configurationHealth,
        recommendedActions,
      },
    };
  }

  /**
   * Parse Zod validation error string into structured ValidationError format
   *
   * Converts Zod's JSON error format or plain text errors into a structured
   * ValidationError object for consistent error handling.
   *
   * @param errorString - Error string from Zod validation
   * @returns Structured ValidationError object
   */
  parseValidationError(errorString: string): ValidationError {
    // Try to parse JSON array of Zod errors
    try {
      const parsed = JSON.parse(errorString);
      if (Array.isArray(parsed) && parsed.length > 0) {
        const firstError = parsed[0];

        // Build path from array
        const path = firstError.path ? firstError.path.join('.') : 'unknown';

        // Extract specific error details
        return {
          code: firstError.code || 'VALIDATION_ERROR',
          message: firstError.message || errorString,
          path,
          severity: 'error',
          category: 'schema',
        };
      }
    } catch {
      // Not JSON, parse as plain text
    }

    // Check for specific known error patterns in the string
    if (errorString.includes('version') && (errorString.includes('empty') || errorString.includes('Required'))) {
      return {
        code: 'INVALID_VERSION',
        message: 'Version field is required and cannot be empty',
        path: 'version',
        severity: 'error',
        category: 'schema',
      };
    }

    if (errorString.includes('applyHardAssertions') && errorString.includes('boolean')) {
      return {
        code: 'INVALID_TYPE',
        message: 'applyHardAssertions must be a boolean value',
        path: 'processingConfig.settings.initialization.applyHardAssertions',
        severity: 'error',
        category: 'schema',
      };
    }

    if (errorString.includes('highConfidence') && (errorString.includes('1.5') || errorString.includes('exceeds'))) {
      return {
        code: 'INVALID_RANGE',
        message: 'highConfidence must be between 0 and 1',
        path: 'processingConfig.confidenceThresholds.highConfidence',
        severity: 'error',
        category: 'schema',
      };
    }

    if (errorString.includes('mediumConfidence') && errorString.includes('negative')) {
      return {
        code: 'INVALID_RANGE',
        message: 'mediumConfidence must be non-negative',
        path: 'processingConfig.confidenceThresholds.mediumConfidence',
        severity: 'error',
        category: 'schema',
      };
    }

    // Default fallback
    return {
      code: 'VALIDATION_ERROR',
      message: errorString,
      path: 'configuration',
      severity: 'error',
      category: 'schema',
    };
  }

  /**
   * Detect rule conflicts (duplicate patterns in different categories)
   *
   * Checks for hard assertion patterns that appear in multiple categories,
   * which would cause ambiguous classification results.
   *
   * @param config - Category configuration to check
   * @returns Array of validation errors for detected conflicts
   */
  detectRuleConflicts(config: CategoryConfiguration): ValidationError[] {
    const errors: ValidationError[] = [];
    const subjectPrefixMap = new Map<string, string[]>();
    const fromAddressMap = new Map<string, string[]>();

    // Skip if categorySignals is not defined
    if (!config.processingConfig?.categorySignals) {
      return errors;
    }

    // Collect all hard assertion patterns
    for (const [categoryName, signals] of Object.entries(config.processingConfig.categorySignals)) {
      // Check subject prefixes
      if (signals.hardAssertions?.subjectPrefixes) {
        for (const prefix of signals.hardAssertions.subjectPrefixes) {
          const existing = subjectPrefixMap.get(prefix) || [];
          existing.push(categoryName);
          subjectPrefixMap.set(prefix, existing);
        }
      }

      // Check from addresses
      if (signals.hardAssertions?.fromAddresses) {
        for (const address of signals.hardAssertions.fromAddresses) {
          const existing = fromAddressMap.get(address) || [];
          existing.push(categoryName);
          fromAddressMap.set(address, existing);
        }
      }
    }

    // Report duplicate subject prefixes
    for (const [pattern, categories] of Array.from(subjectPrefixMap.entries())) {
      if (categories.length > 1) {
        errors.push({
          code: 'RULE_CONFLICT',
          message: `duplicate hard assertion pattern "${pattern}" found in categories: ${categories.join(', ')}`,
          path: `categorySignals.hardAssertions.subjectPrefixes`,
          severity: 'error',
          category: 'logic',
          suggestion: 'Remove duplicate pattern or make it unique to one category',
        });
      }
    }

    // Report duplicate from addresses
    for (const [address, categories] of Array.from(fromAddressMap.entries())) {
      if (categories.length > 1) {
        errors.push({
          code: 'RULE_CONFLICT',
          message: `duplicate hard assertion address "${address}" found in categories: ${categories.join(', ')}`,
          path: `categorySignals.hardAssertions.fromAddresses`,
          severity: 'error',
          category: 'logic',
          suggestion: 'Remove duplicate address or make it unique to one category',
        });
      }
    }

    return errors;
  }

  /**
   * Validate attribute matrix completeness
   *
   * Checks that all attributes referenced in bonus maps and relevance matrices
   * are actually defined in the attributes schema.
   *
   * @param config - Category configuration to check
   * @returns Array of validation errors for undefined attributes
   */
  validateAttributeMatrix(config: CategoryConfiguration): ValidationError[] {
    const errors: ValidationError[] = [];

    // Skip if attributes are not defined
    if (!config.processingConfig?.attributes?.schema) {
      return errors;
    }

    const definedAttributes = new Set(Object.keys(config.processingConfig.attributes.schema));

    // Check that all attributes in bonus map are defined in schema
    if (config.processingConfig.attributes.attributeBonusMap) {
      for (const [categoryName, bonusMap] of Object.entries(config.processingConfig.attributes.attributeBonusMap)) {
        for (const attributeName of Object.keys(bonusMap)) {
          if (!definedAttributes.has(attributeName)) {
            errors.push({
              code: 'UNDEFINED_ATTRIBUTE',
              message: `Attribute "${attributeName}" used in ${categoryName} bonus map but not defined in schema`,
              path: `attributes.attributeBonusMap.${categoryName}.${attributeName}`,
              severity: 'error',
              category: 'reference',
              suggestion: `Add "${attributeName}" to attributes.schema or remove from bonus map`,
            });
          }
        }
      }
    }

    // Check attribute relevance matrix completeness
    if (config.processingConfig.attributeRelevance) {
      for (const [categoryName, relevance] of Object.entries(config.processingConfig.attributeRelevance)) {
        if (categoryName === 'RolesLegend') continue;

        const categoryRoles = (relevance as { categoryRoles?: Record<string, string> }).categoryRoles;
        if (categoryRoles) {
          for (const attributeName of Object.keys(categoryRoles)) {
            if (!definedAttributes.has(attributeName)) {
              errors.push({
                code: 'UNDEFINED_ATTRIBUTE',
                message: `Attribute "${attributeName}" used in ${categoryName} relevance matrix but not defined in schema`,
                path: `attributeRelevance.${categoryName}.categoryRoles.${attributeName}`,
                severity: 'error',
                category: 'reference',
                suggestion: `Add "${attributeName}" to attributes.schema or remove from relevance matrix`,
              });
            }
          }
        }
      }
    }

    return errors;
  }
}

// Default validator instance
export const configValidator = new ConfigurationValidator();

